scwin.gr_results_oncellclick = async function (row, columnIndex, colid) {
  if (colid == "btAppYn" || colid == "btAppConse") {
    scwin.f_setAssgnResult();
    //적재내역이 등록되어 있으면 BT, 우선권 배정 선택 불가
    if (ds_results.getCellData(row, "rsltsAssgnYn") == "Y") {
      await $c.win.alert($p, "적재내역등록이 끝난 컨테이너는 선택할 수 없습니다.");
      // ds_results.UndoMarked();
      ds_results.undoRow(row);
    }
    //BT와 우선권 배정 둘다 선택할 수 없다.
    if (ds_results.getCellData(row, "rsnRightVsslAppYn") == "1") {
      await $c.win.alert($p, "BT와 우선권 배정을 하나의 컨테이너에 대해서 동시에 진행할 수 없습니다.");
      // ds_results.UndoMarked();
      ds_results.undoRow(row);
    }
    if (colid == "btAppConse" && ds_results.getCellData(row, "btAppConse") == "T") {
      // T
      ds_results.setCellData(row, "btAppYn", 1);
    }
    if (colid == "btAppConse" && ds_results.getCellData(row, "btAppConse") == "N") {
      // F
      ds_results.setCellData(row, "btAppYn", 0);
    }
    scwin.f_setAssgnResult();
  }
};
scwin.gr_results_oncelldblclick = function (row, columnIndex, colid) {
  if (colid == "cntrNo") {
    if (ds_results.getCellData(row, "rsltsAssgnYn") == "N") {
      var dptStnCd = ds_results.getCellData(row, "dptWrkPlCd");
      var arvStnCd = ds_results.getCellData(row, "arvWrkPlCd");
      var onReqDt = ica_signDt.getValue();
      var cntrNo = ds_results.getCellData(row, "cntrNo");
      let src = "/ui/ds/op/wrkrslts/railroadwrkrslts/op_205_01_01b.xml";
      let menuNm = "적재내역등록";
      let menuId = "op_205_01_01b";
      paramObj = {};
      paramObj.pgmInfo = {
        dptStnCd: dptStnCd,
        arvStnCd: arvStnCd,
        onReqDt: onReqDt,
        cntrNo: cntrNo
      };
      $c.win.openMenu($p, menuNm, src, menuId, paramObj);
    }
  }
};
